// frontend/src/App.js
import React, { useState, useEffect, useRef } from 'react';
import './App.css';

function App() {
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(false);

  // Refs for scroll animations
  const heroRef = useRef(null);
  const categoriesRef = useRef(null);
  const featuresRef = useRef(null);
  const jobsRef = useRef(null);
  const ctaRef = useRef(null);

  // Load jobs from backend
  const loadJobs = async () => {
    setLoading(true);
    try {
      const response = await fetch('http://localhost:5000/api/jobs');
      const data = await response.json();
      if (data.success) {
        setJobs(data.data.slice(0, 6));
      }
    } catch (error) {
      console.error('Error loading jobs:', error);
    }
    setLoading(false);
  };

  useEffect(() => {
    loadJobs();

    // Intersection Observer for scroll animations
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          entry.target.classList.add('section-visible');
        }
      });
    }, { threshold: 0.1, rootMargin: '0px 0px -50px 0px' });

    // Observe sections
    if (heroRef.current) observer.observe(heroRef.current);
    if (categoriesRef.current) observer.observe(categoriesRef.current);
    if (featuresRef.current) observer.observe(featuresRef.current);
    if (jobsRef.current) observer.observe(jobsRef.current);
    if (ctaRef.current) observer.observe(ctaRef.current);

    return () => observer.disconnect();
  }, []);

  const categories = [
    { name: 'Cleaning', icon: '🧹', jobs: '120+', color: '#FFF1E6' },
    { name: 'Gardening', icon: '🌿', jobs: '85+', color: '#FFE4D6' },
    { name: 'Moving', icon: '📦', jobs: '64+', color: '#FFD8B1' },
    { name: 'Handyman', icon: '🔧', jobs: '156+', color: '#FFCC99' },
    { name: 'Delivery', icon: '🚚', jobs: '203+', color: '#FFC085' },
    { name: 'Painting', icon: '🎨', jobs: '47+', color: '#FFB56B' }
  ];

  const stats = [
    { value: '5,000+', label: 'Workers' },
    { value: '10,000+', label: 'Jobs Done' }
  ];

  // Smooth scroll function
  const scrollToSection = (ref) => {
    ref.current.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  return (
    <div className="app">
      {/* Navigation */}
      <nav className="navbar">
        <div className="nav-container">
          <div className="logo">
            <span className="logo-icon">🏠</span>
            <span className="logo-text">Ekasilody</span>
          </div>
          <div className="nav-links">
            <a href="#hero" onClick={(e) => { e.preventDefault(); scrollToSection(heroRef); }}>Home</a>
            <a href="#categories" onClick={(e) => { e.preventDefault(); scrollToSection(categoriesRef); }}>Services</a>
            <a href="#jobs" onClick={(e) => { e.preventDefault(); scrollToSection(jobsRef); }}>Jobs</a>
            <a href="#features" onClick={(e) => { e.preventDefault(); scrollToSection(featuresRef); }}>Why Us</a>
          </div>
          <div className="nav-buttons">
            <button className="btn-outline">Sign In</button>
            <button className="btn-primary">Join Now</button>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <section ref={heroRef} className="hero-section" id="hero">
        <div className="hero-content">
          <h1 className="hero-title animate-slide-up">
            Connect with local hustlers for any piece job.
          </h1>
          <p className="hero-subtitle animate-slide-up delay-1">
            Fast, reliable, township service at your fingertips. 
            <span className="hero-tagline"> Asihlale emakhaya!</span>
          </p>
          <div className="hero-buttons animate-slide-up delay-2">
            <button className="btn-primary btn-large pulse">
              📋 Post a Job
            </button>
            <button className="btn-secondary btn-large">
              🔍 Find Work
            </button>
          </div>
          <div className="hero-stats animate-slide-up delay-3">
            {stats.map((stat, index) => (
              <div key={index} className="stat-item">
                <span className="stat-value">{stat.value}</span>
                <span className="stat-label">{stat.label}</span>
              </div>
            ))}
          </div>
        </div>
        <div className="hero-image animate-fade-in">
          <img 
            src="/images/hero-banner.png" 
            alt="Township workers" 
            className="hero-banner"
            onError={(e) => {
              e.target.onerror = null;
              e.target.src = 'https://via.placeholder.com/600x400/FF6B35/ffffff?text=Ekasilody+Hustlers';
            }}
          />
        </div>
      </section>

      {/* Categories Section */}
      <section ref={categoriesRef} className="categories-section" id="categories">
        <div className="container">
          <div className="section-header">
            <h2 className="section-title">Popular Categories</h2>
            <p className="section-subtitle">
              Browse through our most requested service categories
            </p>
          </div>
          <div className="categories-grid">
            {categories.map((category, index) => (
              <div 
                key={index} 
                className="category-card animate-on-scroll"
                style={{ backgroundColor: category.color, animationDelay: `${index * 0.1}s` }}
              >
                <div className="category-icon">{category.icon}</div>
                <div className="category-info">
                  <h3 className="category-name">{category.name}</h3>
                  <p className="category-jobs">{category.jobs} jobs</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Why Choose Us Section */}
      <section ref={featuresRef} className="features-section" id="features">
        <div className="container">
          <div className="section-header">
            <h2 className="section-title">Why Choose Us</h2>
            <p className="section-subtitle">We make it easy to get things done</p>
          </div>
          <div className="features-grid">
            <div className="feature-card animate-on-scroll">
              <div className="feature-icon trusted">🛡️</div>
              <h3 className="feature-title">Trusted Hustlers</h3>
              <p className="feature-description">
                All our hustlers are verified locals from the hood
              </p>
            </div>
            <div className="feature-card animate-on-scroll delay-1">
              <div className="feature-icon quick">⚡</div>
              <h3 className="feature-title">Quick Connect</h3>
              <p className="feature-description">
                Get connected with workers in minutes, sharp sharp!
              </p>
            </div>
            <div className="feature-card animate-on-scroll delay-2">
              <div className="feature-icon quality">⭐</div>
              <h3 className="feature-title">Quality Work</h3>
              <p className="feature-description">
                Only the best hustlers, guaranteed satisfaction
              </p>
            </div>
          </div>
        </div>
      </section>

      {/* Recent Jobs Section */}
      <section ref={jobsRef} className="jobs-section" id="jobs">
        <div className="container">
          <div className="section-header">
            <h2 className="section-title">Recent Jobs</h2>
            <p className="section-subtitle">Latest opportunities near you</p>
          </div>
          {loading ? (
            <div className="loading-spinner">Loading...</div>
          ) : (
            <div className="jobs-grid">
              {jobs.map((job, index) => (
                <div key={job.id} className="job-card animate-on-scroll" style={{ animationDelay: `${index * 0.1}s` }}>
                  <div className="job-category">
                    <span className="category-badge">{job.category || 'General'}</span>
                  </div>
                  <h3 className="job-title">{job.title}</h3>
                  <p className="job-description">{job.description}</p>
                  <div className="job-details">
                    <div className="job-location">
                      <span className="location-icon">📍</span>
                      <span>{job.township}</span>
                    </div>
                    <div className="job-date">
                      <span className="date-icon">📅</span>
                      <span>{new Date(job.created_at).toLocaleDateString()}</span>
                    </div>
                    <div className="job-hours">
                      <span className="hours-icon">⏱️</span>
                      <span>{job.estimated_hours || '2-4'} hours</span>
                    </div>
                  </div>
                  <div className="job-footer">
                    <span className="job-budget">R {job.budget_min} - R {job.budget_max}</span>
                    <button className="btn-apply">Apply →</button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </section>

      {/* CTA Section */}
      <section ref={ctaRef} className="cta-section">
        <div className="container">
          <div className="cta-content">
            <h2 className="cta-title animate-pop">Ready to Hustle?</h2>
            <p className="cta-subtitle animate-slide-up">
              Join thousands of ekasi hustlers making moves every day 🏅
            </p>
            <div className="cta-buttons animate-slide-up delay-1">
              <button className="btn-primary btn-large pulse">Post Your First Job</button>
              <button className="btn-secondary btn-large">Start Earning Today</button>
            </div>
          </div>
        </div>
      </section>

      {/* Footer */}
      <footer className="footer">
        <div className="container">
          <div className="footer-grid">
            <div className="footer-section">
              <div className="footer-logo">
                <span className="logo-icon">🏠</span>
                <span className="logo-text">Ekasilody</span>
              </div>
              <p className="footer-tagline">Siyaphanda!</p>
            </div>

            <div className="footer-section">
              <h4 className="footer-title">For Clients</h4>
              <ul className="footer-links">
                <li><a href="#post-job">Post a Job</a></li>
                <li><a href="#services">Browse Services</a></li>
                <li><a href="#how-it-works">How it Works</a></li>
              </ul>
            </div>

            <div className="footer-section">
              <h4 className="footer-title">For Workers</h4>
              <ul className="footer-links">
                <li><a href="#find-work">Find Work</a></li>
                <li><a href="#create-profile">Create Profile</a></li>
                <li><a href="#earnings">Earnings</a></li>
              </ul>
            </div>

            <div className="footer-section">
              <h4 className="footer-title">Support</h4>
              <ul className="footer-links">
                <li><a href="#help">Help Center</a></li>
                <li><a href="#safety">Safety Tips</a></li>
                <li><a href="#contact">Contact Us</a></li>
              </ul>
            </div>
          </div>

          <div className="footer-bottom">
            <p>© 2024 Ekasilody. Siyaphanda!</p>
          </div>
        </div>
      </footer>

      {/* Scroll to Top Button */}
      <button 
        className="scroll-top"
        onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
      >
        ↑
      </button>
    </div>
  );
}

export default App;
